struct Puzzel<SudokuType: SudokuTypeProtocol>: Sendable {
    
    let string: String
    let solutionString: String
    let board: SudokuBoard<SudokuType>
    let solution: SudokuBoard<SudokuType>
    
    init(_ string: String, solution: String) {
        self.string = string
        self.solutionString = solution
        self.board = try! SudokuBoard<SudokuType>(string)
        self.solution = try! SudokuBoard<SudokuType>(solutionString)
    }

}

